// Iterative, fastest
function gcd(a, b) {
  a = Math.abs(a); b = Math.abs(b);
  while (b !== 0) {
    [a, b] = [b, a % b];
  }
  return a;
}

function gcdRecursive(a, b) {
  return b === 0 ? Math.abs(a) : gcdRecursive(b, Math.abs(a % b));
}

function gcdBigInt(a, b) {
  a = a < 0n ? -a : a; b = b < 0n ? -b : b;
  while (b !== 0n) [a, b] = [b, a % b];
  return a;
}
